"""
T2 Order System — Product Routes (Sample 2)

Evolutionary variant: uses standalone serializer functions
rather than model methods or inline dict construction.
This keeps serialization concerns separated from both
the ORM model and the route handlers.
"""

from flask import Blueprint, request, jsonify
from app import db
from models import Product

product_bp = Blueprint('product_bp', __name__)


# ── Serialization layer ──────────────────────────────────────

def serialize_product(product):
    """Convert a single Product ORM object to a plain dict.

    Designed to be reused by order routes when they need to
    embed product details in order responses.
    """
    return {
        'id': product.id,
        'name': product.name,
        'price': product.price,
        'stock': product.stock,
    }


def serialize_products(products):
    """Serialize a single product or a list of products.

    Accepts either a Product instance or an iterable of Products,
    so callers don't need to think about single-vs-list branching.
    """
    if products is None:
        return []
    if isinstance(products, Product):
        return serialize_product(products)
    return [serialize_product(p) for p in products]


# ── Response helpers ─────────────────────────────────────────

def error_response(message, status_code):
    """Build a standardized error JSON response."""
    body = {'status': 'error', 'message': message}
    return jsonify(body), status_code


def ok_response(data, status_code=200):
    """Build a standardized success JSON response."""
    body = {'status': 'ok', 'data': data}
    return jsonify(body), status_code


# ── Routes ───────────────────────────────────────────────────

@product_bp.route('/products', methods=['GET'])
def list_products():
    products = Product.query.all()
    return ok_response(serialize_products(products))


@product_bp.route('/products', methods=['POST'])
def create_product():
    payload = request.get_json(silent=True)
    if payload is None:
        return error_response('Request body must be valid JSON', 400)

    required_fields = ('name', 'price', 'stock')
    for field in required_fields:
        if field not in payload:
            return error_response(f'Missing required field: {field}', 400)

    product = Product(
        name=payload['name'],
        price=float(payload['price']),
        stock=int(payload['stock']),
    )
    db.session.add(product)
    db.session.commit()

    return ok_response(serialize_product(product), status_code=201)


@product_bp.route('/products/<int:product_id>', methods=['GET'])
def get_product(product_id):
    product = Product.query.get(product_id)
    if product is None:
        return error_response(f'Product {product_id} not found', 404)

    return ok_response(serialize_product(product))

"""
T2 Order System -- Product Routes (Sample 1)

Strategy: Explicit serialization helper + manual field validation.
This variant uses a dedicated serialize_product() function and validates
input fields one-by-one with descriptive error messages before committing.
"""

from flask import Blueprint, request, jsonify

product_bp = Blueprint('product_bp', __name__)


def _serialize(product):
    """Convert a Product ORM object to a plain dict."""
    return {
        'id': product.id,
        'name': product.name,
        'price': product.price,
        'stock': product.stock,
    }


def _ok(data=None, status_code=200):
    """Build a standard success response."""
    body = {'status': 'ok'}
    if data is not None:
        body['data'] = data
    return jsonify(body), status_code


def _err(message, status_code=400):
    """Build a standard error response."""
    return jsonify({'status': 'error', 'message': message}), status_code


@product_bp.route('/products', methods=['GET'])
def list_products():
    from app import db
    from models import Product

    products = Product.query.all()
    return _ok([_serialize(p) for p in products])


@product_bp.route('/products', methods=['POST'])
def create_product():
    from app import db
    from models import Product

    payload = request.get_json(silent=True)
    if payload is None:
        return _err('Request body must be valid JSON')

    # Validate required fields individually for clear error reporting
    name = payload.get('name')
    if not name or not isinstance(name, str) or not name.strip():
        return _err('Field "name" is required and must be a non-empty string')

    price = payload.get('price')
    if price is None:
        return _err('Field "price" is required')
    try:
        price = float(price)
    except (ValueError, TypeError):
        return _err('Field "price" must be a number')

    stock = payload.get('stock')
    if stock is None:
        return _err('Field "stock" is required')
    try:
        stock = int(stock)
    except (ValueError, TypeError):
        return _err('Field "stock" must be an integer')

    product = Product(name=name.strip(), price=price, stock=stock)
    db.session.add(product)
    db.session.commit()

    return _ok(_serialize(product), status_code=201)


@product_bp.route('/products/<int:product_id>', methods=['GET'])
def get_product(product_id):
    from app import db
    from models import Product

    product = Product.query.get(product_id)
    if product is None:
        return _err(f'Product {product_id} not found', status_code=404)

    return _ok(_serialize(product))

