"""
T2 Order System — Order Routes (Sample 1)

Evolutionary variant: data-driven state machine using dictionary maps
for transitions and side-effects, with a single generic transition
handler that eliminates duplicated state-change logic.

Design decisions:
- TRANSITIONS dict maps each status to its set of allowed next statuses
- ACTION_MAP binds each target status to its side-effect callback
- A unified _transition_order() handles validation, action dispatch,
  and timestamp setting for pay/ship/deliver/cancel in one place
- Inventory deduction is coupled to the 'paid' action, restoration
  to the 'cancelled' action (conditional on prior 'paid' status)
"""

from datetime import datetime
from flask import Blueprint, request, jsonify
from app import db
from models import Product, Order, OrderItem, PaymentRequest

order_bp = Blueprint('order_bp', __name__)


# ── State Machine Definition ───────────────────────────────────

TRANSITIONS = {
    'pending': {'paid', 'cancelled'},
    'paid':    {'shipped', 'cancelled'},
    'shipped': {'delivered'},
    'delivered': set(),
    'cancelled': set(),
}


def _deduct_stock(order):
    """Reduce product stock for every item in the order."""
    for item in order.items:
        product = Product.query.get(item.product_id)
        product.stock -= item.quantity
    db.session.add(order)


def _restore_stock(order):
    """Restore product stock (used when cancelling a paid order)."""
    for item in order.items:
        product = Product.query.get(item.product_id)
        product.stock += item.quantity


def _no_op(order):
    """No-op action for state changes without side-effects."""
    pass


ACTION_MAP = {
    'paid':      _deduct_stock,
    'shipped':   _no_op,
    'delivered': _no_op,
    'cancelled': _no_op,
}

TIMESTAMP_FIELDS = {
    'paid':      'paid_at',
    'shipped':   'shipped_at',
    'delivered': 'delivered_at',
    'cancelled': 'cancelled_at',
}


# ── Serialization ──────────────────────────────────────────────

def serialize_order_item(item):
    return {
        'id': item.id,
        'product_id': item.product_id,
        'quantity': item.quantity,
        'unit_price': item.unit_price,
    }


def serialize_order(order, include_items=False):
    data = {
        'id': order.id,
        'user_id': order.user_id,
        'status': order.status,
        'total_amount': order.total_amount,
        'created_at': order.created_at.isoformat() if order.created_at else None,
    }
    if include_items:
        data['items'] = [serialize_order_item(i) for i in order.items]
    return data


# ── Response Helpers ───────────────────────────────────────────

def ok_response(data, status_code=200):
    return jsonify({'status': 'ok', 'data': data}), status_code


def error_response(message, status_code):
    return jsonify({'status': 'error', 'message': message}), status_code


# ── Generic State Transition ───────────────────────────────────

def _transition_order(order_id, target_status):
    """Validate and execute a state transition on an order.

    Returns (order, error_tuple) where error_tuple is None on success
    or (message, status_code) on failure.
    """
    order = Order.query.get(order_id)
    if order is None:
        return None, (f'Order {order_id} not found', 404)

    if target_status not in TRANSITIONS.get(order.status, set()):
        return order, (
            f'Cannot transition from {order.status} to {target_status}',
            409,
        )

    previous_status = order.status
    order.status = target_status

    # Execute side-effect action for the new status
    action = ACTION_MAP.get(target_status, _no_op)
    action(order)

    # Special case: cancelling a paid order must restore stock
    if target_status == 'cancelled' and previous_status == 'paid':
        _restore_stock(order)

    # Set timestamp
    ts_field = TIMESTAMP_FIELDS.get(target_status)
    if ts_field:
        setattr(order, ts_field, datetime.utcnow())

    db.session.commit()
    return order, None


# ── Order CRUD Routes ──────────────────────────────────────────

@order_bp.route('/orders', methods=['POST'])
def create_order():
    payload = request.get_json(silent=True)
    if payload is None:
        return error_response('Request body must be valid JSON', 400)

    required_fields = ('user_id', 'items')
    for field in required_fields:
        if field not in payload:
            return error_response(f'Missing required field: {field}', 400)

    items_data = payload['items']
    if not items_data or not isinstance(items_data, list):
        return error_response('items must be a non-empty list', 400)

    # Validate products and calculate total
    total_amount = 0.0
    order_items = []
    for entry in items_data:
        product = Product.query.get(int(entry['product_id']))
        if product is None:
            return error_response(
                f'Product {entry["product_id"]} not found', 400)
        quantity = int(entry['quantity'])
        if quantity > product.stock:
            return error_response(
                f'Insufficient stock for product {product.id} '
                f'(requested {quantity}, available {product.stock})', 400)

        total_amount += product.price * quantity
        order_items.append({
            'product': product,
            'quantity': quantity,
            'unit_price': product.price,
        })

    # Create order and items
    order = Order(
        user_id=payload['user_id'],
        status='pending',
        total_amount=total_amount,
    )
    db.session.add(order)
    db.session.flush()  # get order.id

    for item_info in order_items:
        item = OrderItem(
            order_id=order.id,
            product_id=item_info['product'].id,
            quantity=item_info['quantity'],
            unit_price=item_info['unit_price'],
        )
        db.session.add(item)

    db.session.commit()
    return ok_response(serialize_order(order), status_code=201)


@order_bp.route('/orders/<int:order_id>', methods=['GET'])
def get_order(order_id):
    order = Order.query.get(order_id)
    if order is None:
        return error_response(f'Order {order_id} not found', 404)
    return ok_response(serialize_order(order, include_items=True))


@order_bp.route('/orders', methods=['GET'])
def list_orders():
    query = Order.query
    user_id = request.args.get('user_id')
    status = request.args.get('status')
    if user_id:
        query = query.filter(Order.user_id == user_id)
    if status:
        query = query.filter(Order.status == status)
    orders = query.all()
    return ok_response([serialize_order(o) for o in orders])


# ── State Machine Routes ───────────────────────────────────────

@order_bp.route('/orders/<int:order_id>/pay', methods=['POST'])
def pay_order(order_id):
    idempotency_key = request.headers.get('Idempotency-Key')
    if not idempotency_key:
        return error_response('Missing Idempotency-Key header', 400)

    # Check for existing idempotent request
    existing = PaymentRequest.query.filter_by(
        idempotency_key=idempotency_key
    ).first()
    if existing:
        order = Order.query.get(order_id)
        if order is None:
            return error_response(f'Order {order_id} not found', 404)
        return ok_response(serialize_order(order))

    # Validate order exists before recording payment
    order = Order.query.get(order_id)
    if order is None:
        return error_response(f'Order {order_id} not found', 404)

    order, err = _transition_order(order_id, 'paid')
    if err:
        return error_response(err[0], err[1])

    # Record the payment request for idempotency
    payment = PaymentRequest(
        order_id=order_id,
        idempotency_key=idempotency_key,
        status='completed',
    )
    db.session.add(payment)
    db.session.commit()

    return ok_response(serialize_order(order))


@order_bp.route('/orders/<int:order_id>/ship', methods=['POST'])
def ship_order(order_id):
    order, err = _transition_order(order_id, 'shipped')
    if err:
        return error_response(err[0], err[1])
    return ok_response(serialize_order(order))


@order_bp.route('/orders/<int:order_id>/deliver', methods=['POST'])
def deliver_order(order_id):
    order, err = _transition_order(order_id, 'delivered')
    if err:
        return error_response(err[0], err[1])
    return ok_response(serialize_order(order))


@order_bp.route('/orders/<int:order_id>/cancel', methods=['POST'])
def cancel_order(order_id):
    order, err = _transition_order(order_id, 'cancelled')
    if err:
        return error_response(err[0], err[1])
    return ok_response(serialize_order(order))

